digraph MAS_Topology {
    rankdir=LR;
    node [shape=box, style="rounded,filled", fontname="DejaVu Sans Mono"];
    edge [color="#666666", penwidth=1.5];

    /* Entry/Exit */
    input [shape=ellipse, label="INPUT", fillcolor="#E3F2FD", color="#1976D2"];
    output [shape=ellipse, label="OUTPUT", fillcolor="#FFEBEE", color="#C62828"];
    FundamentalAgent [label="FundamentalAgent\nweight=0.25", fillcolor="#4CAF5040", color="#4CAF50"];
    QuantAgent [label="QuantAgent\nweight=0.25", fillcolor="#4CAF5040", color="#4CAF50"];
    MacroAgent [label="MacroAgent\nweight=0.15", fillcolor="#4CAF5040", color="#4CAF50"];
    GroundingLoop [label="GroundingLoop\nweight=0.1", fillcolor="#4CAF5040", color="#4CAF50"];

    /* Connections */
    router -> FundamentalAgent;
    router -> QuantAgent;
    FundamentalAgent -> merge;
    QuantAgent -> merge;
    merge -> synthesis;

    input -> router [style=dashed, color="#1976D2"];
    synthesis -> output [style=dashed, color="#C62828"];

    subgraph cluster_legend {
        label="Legend"; fontsize=12;
        style=dashed; color="#999999";
        leg1 [shape=box, label="Agent", fillcolor="#4CAF5040"];
        leg2 [shape=diamond, label="Switch", fillcolor="#FF980040"];
    }
}
